SELECT DISTINCT resorts.name, resorts.location, resorts.phone_number
FROM resorts
INNER JOIN reviews ON resorts.resort_id = reviews.resort_id;

SELECT AVG(difficulty_score) AS Average_Difficulty_Score
FROM resorts
WHERE location = 'Lake Geneva, WI';

SELECT resort_id, name
FROM resorts
WHERE summit_elevation < 14000;
